INSERT INTO "public"."messages" ("message", "language", "length", "created_at", "updated_at") VALUES
('Dzisiaj słońce świeci dla Ciebie. Pamiętaj, że każdy dzień to nowa szansa na szczęście.', 'PL', 89, NOW(), NOW()),
('Wieczorem, gdy świat się uspokaja, Twoje serce może znów bić spokojnie. Jesteś bezpieczna.', 'PL', 95, NOW(), NOW()),
('W cichych chwilach wieczoru znajdź czas dla siebie. Ty też zasługujesz na miłość i spokój.', 'PL', 87, NOW(), NOW()),
('Każdy wieczór to nowy początek. Jutro może być piękniejsze niż dzisiaj. Wierz w to.', 'PL', 82, NOW(), NOW()),
('W blasku księżyca znajdź siłę. W ciemności nocy znajdź nadzieję. Jesteś silniejsza niż myślisz.', 'PL', 98, NOW(), NOW()),
('Dzisiaj był dobry dzień. Jutro będzie jeszcze lepszy. Ty tworzysz swoje szczęście.', 'PL', 76, NOW(), NOW()),
('W wieczornym świetle znajdź spokój. W cichych myślach znajdź odpowiedzi. Wszystko będzie dobrze.', 'PL', 92, NOW(), NOW()),
('Każdy wieczór to czas na refleksję. Każdy poranek to czas na nowe marzenia. Żyj pełnią życia.', 'PL', 88, NOW(), NOW()),
('W blasku gwiazd znajdź inspirację. W cichym szeleście liści znajdź spokój. Jesteś częścią pięknego świata.', 'PL', 105, NOW(), NOW()),
('Dzisiaj podziękuj sobie za to, kim jesteś. Jutro pokaż światu, kim możesz być. Jesteś wyjątkowa.', 'PL', 96, NOW(), NOW());
